package main.rice.obj;

import java.util.Objects;

/**
 * Abstract base class for all Python objects.
 * @param <T> the underlying Java type representing the Python value
 */
public abstract class APyObj<T> {

    protected T value;

    public APyObj(T value) {
        this.value = value;
    }

    /**
     * Returns the underlying Java value.
     */
    public T getValue() {
        return value;
    }

    /**
     * Returns a Python-style string representation.
     */
    @Override
    public abstract String toString();

    /**
     * Two APyObj instances are equal iff they have the exact same class and equal values.
     */
    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null || getClass() != obj.getClass()) return false;
        APyObj<?> other = (APyObj<?>) obj;
        return Objects.equals(value, other.value);
    }

    @Override
    public int hashCode() {
        return Objects.hashCode(value);
    }
}

