/**
 * Abstract base class for all iterable Python objects.
 * @param <T> the collection type (e.g., List<PyIntObj>, Set<PyIntObj>)
 */
public abstract class AIterablePyObj<T> extends APyObj<T> {

    public AIterablePyObj(T value) {
        super(value);
    }
}

package main.rice.obj;

/**
 * Represents a Python boolean object (True or False).
 */
public class PyBoolObj extends APyObj<Boolean> {

    public PyBoolObj(Boolean value) {
        super(value);
    }

    @Override
    public String toString() {
        return value ? "True" : "False";
    }
}

