package main.rice.obj;

import java.util.List;
import java.util.StringJoiner;

/**
 * Represents a Python list object.
 * @param <T> the type of elements in the list
 */
public class PyListObj<T extends APyObj<?>> extends AIterablePyObj<List<T>> {

    public PyListObj(List<T> value) {
        super(value);
    }

    @Override
    public String toString() {
        StringJoiner sj = new StringJoiner(", ", "[", "]");
        for (T elem : value) {
            sj.add(elem.toString());
        }
        return sj.toString();
    }
}

package main.rice.obj;

import java.util.List;
import java.util.StringJoiner;

/**
 * Represents a Python tuple object.
 * @param <T> the type of elements in the tuple
 */
public class PyTupleObj<T extends APyObj<?>> extends AIterablePyObj<List<T>> {

    public PyTupleObj(List<T> value) {
        super(value);
    }

    @Override
    public String toString() {
        if (value.isEmpty()) {
            return "()";
        }
        if (value.size() == 1) {
            return "(" + value.get(0).toString() + ",)";
        }
        StringJoiner sj = new StringJoiner(", ", "(", ")");
        for (T elem : value) {
            sj.add(elem.toString());
        }
        return sj.toString();
    }
}

