package main.rice.obj;

import java.util.Map;
import java.util.StringJoiner;

/**
 * Represents a Python dictionary object.
 * @param <K> the type of keys
 * @param <V> the type of values
 */
public class PyDictObj<K extends APyObj<?>, V extends APyObj<?>> extends AIterablePyObj<Map<K, V>> {

    public PyDictObj(Map<K, V> value) {
        super(value);
    }

    @Override
    public String toString() {
        if (value.isEmpty()) {
            return "{}";
        }
        StringJoiner sj = new StringJoiner(", ", "{", "}");
        for (Map.Entry<K, V> entry : value.entrySet()) {
            sj.add(entry.getKey().toString() + ": " + entry.getValue().toString());
        }
        return sj.toString();
    }
}

package main.rice.obj;

import java.util.ArrayList;
import java.util.List;

/**
 * Represents a Python string object.
 * Internally stores a list of PyCharObj elements.
 */
public class PyStringObj extends AIterablePyObj<List<PyCharObj>> {

    public PyStringObj(String str) {
        super(toCharList(str));
    }

    private static List<PyCharObj> toCharList(String str) {
        List<PyCharObj> chars = new ArrayList<>();
        for (char c : str.toCharArray()) {
            chars.add(new PyCharObj(c));
        }
        return chars;
    }

    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("'");
        for (PyCharObj c : value) {
            sb.append(c.getValue());
        }
        sb.append("'");
        return sb.toString();
    }
}
